patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..70acb9363178 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1850,6 +1850,102 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }

+
+  // Check for comparisons of the same value against different constants.
+  // Pattern: (fcmp pred X, C0) {and|or} (fcmp pred X, C1)
+  // For AND: take the more restrictive comparison
+  // For OR: take the less restrictive comparison
+  const APFloat *C0 = nullptr, *C1 = nullptr;
+  Value *X = nullptr;
+  FCmpInst::Predicate Pred = PredL;
+  bool PredSwapped = false;
+
+  // Check if both comparisons have the same value on the left side
+  if (PredL == PredR && FCmpInst::isOrdered(PredL) &&
+      LHS0 == RHS0 &&
+      match(LHS1, m_APFloat(C0)) && match(RHS1, m_APFloat(C1))) {
+    X = LHS0;
+  }
+  // Check if both comparisons have the same value on the right side (commuted)
+  else if (PredL == PredR && FCmpInst::isOrdered(PredL) &&
+           LHS1 == RHS1 &&
+           match(LHS0, m_APFloat(C0)) && match(RHS0, m_APFloat(C1))) {
+    X = LHS1;
+    Pred = FCmpInst::getSwappedPredicate(PredL);
+    PredSwapped = true;
+  }
+  // Check LHS0 == RHS1 (cross comparison with swapped RHS predicate)
+  else if (PredL == PredR && FCmpInst::isOrdered(PredL) &&
+           LHS0 == RHS1 &&
+           match(LHS1, m_APFloat(C0)) && match(RHS0, m_APFloat(C1))) {
+    X = LHS0;
+    Pred = FCmpInst::getSwappedPredicate(PredR);
+    PredSwapped = true;
+  }
+  // Check LHS1 == RHS0 (cross comparison with swapped LHS predicate)
+  else if (PredL == PredR && FCmpInst::isOrdered(PredL) &&
+           LHS1 == RHS0 &&
+           match(LHS0, m_APFloat(C0)) && match(RHS1, m_APFloat(C1))) {
+    X = LHS1;
+    Pred = FCmpInst::getSwappedPredicate(PredL);
+  }
+
+  if (X) {
+    // Compare constants to determine range containment
+    APFloat::cmpResult Cmp = C0->compare(*C1);
+    bool LHSContainsRHS = false, RHSContainsLHS = false;
+
+    switch (Pred) {
+    case FCmpInst::FCMP_OLT:
+      // X < C0 contains X < C1 iff C0 > C1
+      LHSContainsRHS = (Cmp == APFloat::cmpGreaterThan);
+      RHSContainsLHS = (Cmp == APFloat::cmpLessThan);
+      break;
+    case FCmpInst::FCMP_OLE:
+      // X <= C0 contains X <= C1 iff C0 >= C1
+      LHSContainsRHS = (Cmp == APFloat::cmpGreaterThan || Cmp == APFloat::cmpEqual);
+      RHSContainsLHS = (Cmp == APFloat::cmpLessThan || Cmp == APFloat::cmpEqual);
+      break;
+    case FCmpInst::FCMP_OGT:
+      // X > C0 contains X > C1 iff C0 < C1
+      LHSContainsRHS = (Cmp == APFloat::cmpLessThan);
+      RHSContainsLHS = (Cmp == APFloat::cmpGreaterThan);
+      break;
+    case FCmpInst::FCMP_OGE:
+      // X >= C0 contains X >= C1 iff C0 <= C1
+      LHSContainsRHS = (Cmp == APFloat::cmpLessThan || Cmp == APFloat::cmpEqual);
+      RHSContainsLHS = (Cmp == APFloat::cmpGreaterThan || Cmp == APFloat::cmpEqual);
+      break;
+    case FCmpInst::FCMP_OEQ:
+      // X == C0 and X == C1 only overlap if C0 == C1
+      if (Cmp != APFloat::cmpEqual)
+        return nullptr;
+      return IsAnd ? RHS : LHS;
+    case FCmpInst::FCMP_ONE:
+      // X != C0 OR X != C1 is always true for C0 != C1
+      // X != C0 AND X != C1 cannot be simplified to a single comparison
+      if (!IsAnd && Cmp != APFloat::cmpEqual)
+        return ConstantInt::getTrue(LHS->getType());
+      return nullptr;
+    default:
+      return nullptr;
+    }
+
+    // For AND: return the more restrictive (smaller range)
+    // For OR: return the less restrictive (larger range)
+    if (IsAnd) {
+      if (LHSContainsRHS)
+        return PredSwapped ? LHS : RHS;
+      if (RHSContainsLHS)
+        return PredSwapped ? RHS : LHS;
+    } else {
+      if (LHSContainsRHS)
+        return PredSwapped ? RHS : LHS;
+      if (RHSContainsLHS)
+        return PredSwapped ? LHS : RHS;
+    }
+  }
+
   return nullptr;
 }

